const payload = Array.isArray($json) ? $json : ($json.vehicles || $json.data || []);
const today = new Date();
today.setHours(0, 0, 0, 0);
const lookaheadDays = Number($env.LIFEPILOT_VEHICLE_LOOKAHEAD_DAYS || 90);
const warningDate = new Date(today);
warningDate.setDate(warningDate.getDate() + lookaheadDays);
const reminderLeadDays = Number($env.LIFEPILOT_VEHICLE_REMINDER_LEAD_DAYS || 30);
function parseDate(value) {
  if (!value) return null;
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return null;
  parsed.setHours(0, 0, 0, 0);
  return parsed;
}
function daysUntil(date) {
  return Math.ceil((date.getTime() - today.getTime()) / 86400000);
}
function severityFor(date) {
  const days = daysUntil(date);
  if (days < 0) return 'critical';
  if (days <= 7) return 'urgent';
  if (days <= 30) return 'warning';
  return 'info';
}
function reminderDateFor(date) {
  const reminder = new Date(date);
  reminder.setDate(reminder.getDate() - reminderLeadDays);
  if (reminder < today) return today.toISOString().slice(0, 10);
  return reminder.toISOString().slice(0, 10);
}
function vehicleLabel(vehicle) {
  return [vehicle.brand, vehicle.model, vehicle.registration_masked].filter(Boolean).join(' ') || vehicle.id;
}
const actions = [];
for (const vehicle of payload) {
  const label = vehicleLabel(vehicle);
  const inspectionDue = parseDate(vehicle.technical_inspection_due_date);
  if (inspectionDue && inspectionDue <= warningDate) {
    actions.push({
      type: 'technical_inspection',
      deduplication_key: `vehicle:${vehicle.id}:technical_inspection:${inspectionDue.toISOString().slice(0, 10)}`,
      vehicle_id: vehicle.id,
      user_id: vehicle.user_id || $env.LIFEPILOT_USER_ID,
      title: `Contrôle technique à prévoir - ${label}`,
      description: `Échéance contrôle technique le ${inspectionDue.toISOString().slice(0, 10)}.`,
      due_date: inspectionDue.toISOString().slice(0, 10),
      reminder_date: reminderDateFor(inspectionDue),
      severity: severityFor(inspectionDue),
      source_type: 'vehicle',
      source_id: vehicle.id,
      notification_channels: ['in_app', 'email']
    });
  }
  const insuranceDue = parseDate(vehicle.insurance_due_date || vehicle.insurance_contract?.next_due_date || vehicle.insurance_contract?.end_date || vehicle.insurance_contract?.renewal_date);
  if ((vehicle.insurance_contract_id || vehicle.insurance_contract) && insuranceDue && insuranceDue <= warningDate) {
    actions.push({
      type: 'insurance',
      deduplication_key: `vehicle:${vehicle.id}:insurance:${insuranceDue.toISOString().slice(0, 10)}`,
      vehicle_id: vehicle.id,
      contract_id: vehicle.insurance_contract_id || vehicle.insurance_contract?.id,
      user_id: vehicle.user_id || $env.LIFEPILOT_USER_ID,
      title: `Assurance à vérifier - ${label}`,
      description: `Échéance ou renouvellement d'assurance le ${insuranceDue.toISOString().slice(0, 10)}.`,
      due_date: insuranceDue.toISOString().slice(0, 10),
      reminder_date: reminderDateFor(insuranceDue),
      severity: severityFor(insuranceDue),
      source_type: 'vehicle',
      source_id: vehicle.id,
      notification_channels: ['in_app', 'email']
    });
  }
  const events = vehicle.events || vehicle.maintenance_events || [];
  for (const event of events) {
    const nextDue = parseDate(event.next_due_date);
    const mileageDue = event.next_due_mileage && vehicle.mileage_current && event.next_due_mileage <= vehicle.mileage_current + Number($env.LIFEPILOT_VEHICLE_MILEAGE_LOOKAHEAD || 1500);
    if (!nextDue && !mileageDue) continue;
    if (nextDue && nextDue > warningDate && !mileageDue) continue;
    const dueDate = nextDue || today;
    actions.push({
      type: 'maintenance',
      deduplication_key: `vehicle:${vehicle.id}:maintenance:${event.id || event.title}:${nextDue ? nextDue.toISOString().slice(0, 10) : event.next_due_mileage}`,
      vehicle_id: vehicle.id,
      event_id: event.id,
      user_id: vehicle.user_id || $env.LIFEPILOT_USER_ID,
      title: `Entretien à planifier - ${label}`,
      description: [event.title, nextDue ? `échéance ${nextDue.toISOString().slice(0, 10)}` : null, event.next_due_mileage ? `à ${event.next_due_mileage} km` : null].filter(Boolean).join(' - '),
      due_date: dueDate.toISOString().slice(0, 10),
      reminder_date: reminderDateFor(dueDate),
      severity: mileageDue && !nextDue ? 'warning' : severityFor(dueDate),
      source_type: 'vehicle',
      source_id: vehicle.id,
      notification_channels: ['in_app', 'email']
    });
  }
}
return [{ json: { user_id: $env.LIFEPILOT_USER_ID, generated_at: new Date().toISOString(), action_required: actions.length > 0, count: actions.length, reminders: actions } }];
